    pub fn parse_market(&self, mut market: Value) -> Value {
        let mut id: Value = self.safe_string_k(market.clone(), "symbol", &[]);
        let mut baseId: Value = self.safe_string_k(market.clone(), "baseAsset", &[]);
        let mut quoteId: Value = self.safe_string_k(market.clone(), "quoteAsset", &[]);
        let mut base: Value = self.safe_currency_code(baseId.clone(), &[]);
        let mut quote: Value = self.safe_currency_code(quoteId.clone(), &[]);
        let mut active: Value = Value::Bool(is_equal(&self.safe_string_k(market.clone(), "status", &[]), &Value::Str("TRADING".to_string())));
        let mut spot: Value = Value::Null;
        let mut symbol: Value = Value::Null;
        let mut settle: Value = Value::Null;
        let mut settleId: Value = Value::Null;
        let mut swap: Value = Value::Null;
        let mut linear: Value = Value::Null;
        let mut inverse: Value = Value::Null;
        let mut contractSize: Value = Value::Null;
        let mut contractType: Value = self.safe_string_k(market.clone(), "contractType", &[]);
        let mut isContract: Value = Value::Bool(!is_equal(&contractType, &Value::Null));
        if is_true(&isContract) {
            // currently, there is only perpetuals, not futures
            spot = Value::Bool(false);
            swap = Value::Bool(true);
            settleId = self.safe_string_k(market.clone(), "marginAsset", &[]);
            settle = self.safe_currency_code(settleId.clone(), &[]);
            symbol = add(&add(&add(&add(&base, &Value::Str("/".to_string())), &quote), &Value::Str(":".to_string())), &settle);
            linear = Value::Bool(is_equal(&settle, &quote));
            inverse = Value::Bool(is_equal(&settle, &base));
            contractSize = self.safe_number2(market.clone(), Value::Str("contractSize".to_string()), Value::Str("unit".to_string()), &[self.parse_number(Value::Str("1".to_string()), &[])]);
        }  else {
            spot = Value::Bool(true);
            swap = Value::Bool(false);
            symbol = add(&add(&base, &Value::Str("/".to_string())), &quote);
        }
        // filters
        let mut filters: Value = self.safe_list_k(market.clone(), "filters", &[Value::List(vec![])]);
        let mut filtersByType: Value = self.index_by(filters.clone(), Value::Str("filterType".to_string()));
        let mut filterNotional: Value = self.safe_dict2(filtersByType.clone(), Value::Str("MIN_NOTIONAL".to_string()), Value::Str("NOTIONAL".to_string()), &[]);
        let mut filterPrice: Value = self.safe_dict_k(filtersByType.clone(), "PRICE_FILTER", &[]);
        let mut filterLotSize: Value = self.safe_dict_k(filtersByType.clone(), "LOT_SIZE", &[]);
        let mut filterMarketLotSize: Value = self.safe_dict_k(filtersByType.clone(), "MARKET_LOT_SIZE", &[Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
})]);
        let mut pricePrecision: Value = self.safe_number_k(filterPrice.clone(), "tickSize", &[]);
        if is_equal(&pricePrecision, &Value::Null) {
            pricePrecision = self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "pricePrecision", &[])]), &[]);
        }
        let mut amountPrecision: Value = ternary(is_true(&(!is_equal(&filterLotSize, &Value::Null))), self.safe_number_k(filterLotSize.clone(), "stepSize", &[]), self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "quantityPrecision", &[])]), &[]));
        return self.safe_market_structure(&[Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), id.clone());
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("base".to_string(), base.clone());
        m.insert("quote".to_string(), quote.clone());
        m.insert("settle".to_string(), settle.clone());
        m.insert("baseId".to_string(), baseId.clone());
        m.insert("quoteId".to_string(), quoteId.clone());
        m.insert("settleId".to_string(), settleId.clone());
        m.insert("type".to_string(), ternary(is_true(&isContract), Value::Str("swap".to_string()), Value::Str("spot".to_string())));
        m.insert("spot".to_string(), spot.clone());
        m.insert("margin".to_string(), Value::Bool(false));
        m.insert("swap".to_string(), swap.clone());
        m.insert("future".to_string(), Value::Bool(false));
        m.insert("option".to_string(), Value::Bool(false));
        m.insert("active".to_string(), active.clone());
        m.insert("contract".to_string(), isContract.clone());
        m.insert("linear".to_string(), linear.clone());
        m.insert("inverse".to_string(), inverse.clone());
        m.insert("taker".to_string(), get_value(&get_value(&self.fees, &Value::Str("trading".to_string())), &Value::Str("taker".to_string())));
        m.insert("maker".to_string(), get_value(&get_value(&self.fees, &Value::Str("trading".to_string())), &Value::Str("maker".to_string())));
        m.insert("contractSize".to_string(), contractSize.clone());
        m.insert("expiry".to_string(), Value::Null);
        m.insert("expiryDatetime".to_string(), Value::Null);
        m.insert("strike".to_string(), Value::Null);
        m.insert("optionType".to_string(), Value::Null);
        m.insert("precision".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("amount".to_string(), amountPrecision.clone());
        m.insert("price".to_string(), pricePrecision.clone());
        m.insert("base".to_string(), self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "baseAssetPrecision", &[])]), &[]));
        m.insert("quote".to_string(), self.parse_number(self.parse_precision(&[self.safe_string_k(market.clone(), "quotePrecision", &[])]), &[]));
    m
}));
        m.insert("limits".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("leverage".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("amount".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(filterLotSize.clone(), "minQty", &[]));
        m.insert("max".to_string(), self.safe_number_k(filterLotSize.clone(), "maxQty", &[]));
    m
}));
        m.insert("price".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(filterPrice.clone(), "minPrice", &[]));
        m.insert("max".to_string(), self.safe_number_k(filterPrice.clone(), "maxPrice", &[]));
    m
}));
        m.insert("cost".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number2(filterNotional.clone(), Value::Str("notional".to_string()), Value::Str("minNotional".to_string()), &[]));
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("market".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(filterMarketLotSize.clone(), "minQty", &[]));
        m.insert("max".to_string(), self.safe_number_k(filterMarketLotSize.clone(), "maxQty", &[]));
    m
}));
    m
}));
        m.insert("created".to_string(), self.safe_integer2(market.clone(), Value::Str("listingTime".to_string()), Value::Str("createTime".to_string()), &[]));
        m.insert("info".to_string(), market.clone());
    m
})]);

    Value::Null
}

